<x-app.layouts title="About Hidden Line" description="Learn more about Hidden Line, the ultimate Tor-optimized .onion directory providing verified links, uptime monitoring, and decentralized access.">
    <div class="page-header" style="text-align: center; margin-bottom: 2rem;">
        <h1><i class="fa fa-info-circle" style="color: var(--accent-blue);"></i> About Hidden Line</h1>
        <p>Your privacy-focused, uncensored gateway to the deep web.</p>
